const query = $('Results Webhook').first().json.query || {};
const batchId = (query.batchId || '').toString().trim();
const expected = parseInt(query.expected, 10) || 0;

const rows = $input.all().map((item) => item.json);
const matched = rows.filter((row) => (row.batchId || '').toString().trim() === batchId);

const candidates = matched
  .map((row) => ({
    fileName: row.fileName || '',
    candidateName: row.candidateName || '',
    email: row.email || '',
    phone: row.phone || '',
    yearsExperience: row.yearsExperience || '',
    skills: row.skills || '',
    education: row.education || '',
    certifications: row.certifications || '',
    summary: row.summary || '',
    score: Number(row.score) || 0,
    classification: row.classification || '',
    skillMatchScore: Number(row.skillMatchScore) || 0,
    experienceScore: Number(row.experienceScore) || 0,
    achievementScore: Number(row.achievementScore) || 0,
    educationScore: Number(row.educationScore) || 0,
    clarityScore: Number(row.clarityScore) || 0,
    strengths: row.strengths || '',
    gaps: row.gaps || '',
    recommendation: row.recommendation || '',
    processedAt: row.processedAt || ''
  }))
  .sort((a, b) => b.score - a.score)
  .map((c, i) => ({ ...c, rank: i + 1 }));

const processedCount = candidates.length;

return [{
  json: {
    batchId,
    expected,
    processedCount,
    isComplete: expected > 0 && processedCount >= expected,
    candidates
  }
}];
